import "fmt"

func firstNonEmpty(ss []string) (string, bool) {
	for _, s := range ss {
		if s != "" {
			return s, true
		}
	}
	return "", false
}

func main() { fmt.Println(firstNonEmpty(nil)) }

pub fn split_in_half(s: &str) -> (&str, &str) {
    let target = s.len() / 2;
    let mut mid = target;
    while mid > 0 && !s.is_char_boundary(mid) { mid -= 1; }
    s.split_at(mid)
}
